import React, { useState, useEffect } from 'react';

function Dashboard() {
  const [trashData, setTrashData] = useState([]);
  const [adminData, setAdminData] = useState([]);
  const [activeAdmin, setActiveAdmin] = useState('');

  // 1. Fungsi ambil data sampah & daftar admin dari Flask
  const fetchData = async () => {
    try {
      // Ambil data sampah
      const resTrash = await fetch('http://127.0.0.1:5000/api/trash');
      const resultTrash = await resTrash.json();
      setTrashData(resultTrash);

      // Ambil data admin (Kita buat endpoint baru di Flask nanti)
      const resAdmins = await fetch('http://127.0.0.1:5000/api/admins');
      const resultAdmins = await resAdmins.json();
      setAdminData(resultAdmins);
    } catch (error) {
      console.error("Gagal ambil data:", error);
    }
  };

  useEffect(() => {
    // Ambil nama admin yang sedang login dari memori browser
    const name = localStorage.getItem("nama_aktif");
    setActiveAdmin(name || "Admin");

    fetchData();
    const interval = setInterval(fetchData, 5000); // Auto refresh tiap 5 detik
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={styles.title}>Smart Trash Bin Monitoring</h1>
        <div style={styles.welcomeBox}>
          Selamat Datang, <strong>{activeAdmin}</strong>! 👋
        </div>
      </header>

      {/* --- SECTION 1: STATISTIK --- */}
      <div style={styles.statsContainer}>
        <div style={styles.card}>
          <h3>Total Data Sampah</h3>
          <p style={styles.cardValue}>{trashData.length}</p>
        </div>
        <div style={styles.card}>
          <h3>Total Admin Terdaftar</h3>
          <p style={styles.cardValue}>{adminData.length}</p>
        </div>
      </div>

      {/* --- SECTION 2: TABEL MONITORING SAMPAH --- */}
      <div style={styles.section}>
        <h2 style={styles.sectionTitle}>📊 Data Monitoring Real-time</h2>
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>ID Bin</th>
                <th style={styles.th}>Tipe</th>
                <th style={styles.th}>Kapasitas</th>
                <th style={styles.th}>Status</th>
                <th style={styles.th}>Admin Pemantau</th>
                <th style={styles.th}>Waktu</th>
              </tr>
            </thead>
            <tbody>
              {trashData.map((item, index) => (
                <tr key={index} style={styles.tr}>
                  <td style={styles.td}>{item.bin_id}</td>
                  <td style={styles.td}>{item.type}</td>
                  <td style={styles.td}>
                    <div style={styles.progressBg}>
                      <div style={{...styles.progressFill, width: `${item.percentage}%`}}></div>
                      <span style={{zIndex: 1}}>{Math.round(item.percentage)}%</span>
                    </div>
                  </td>
                  <td style={styles.td}>
                    <span style={item.status === "penuh" ? styles.badgeFull : styles.badgeEmpty}>
                      {item.status}
                    </span>
                  </td>
                  <td style={styles.td}>{item.admin_email || '-'}</td>
                  <td style={styles.td}>{new Date(item.created_at).toLocaleString('id-ID')}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* --- SECTION 3: TABEL DATA ADMIN --- */}
      <div style={styles.section}>
        <h2 style={styles.sectionTitle}>👥 Daftar Admin Sistem</h2>
        <div style={styles.tableContainer}>
          <table style={styles.table}>
            <thead>
              <tr>
                <th style={styles.th}>Nama Admin</th>
                <th style={styles.th}>Email</th>
                <th style={styles.th}>Password (Encrypted)</th>
              </tr>
            </thead>
            <tbody>
              {adminData.map((admin, index) => (
                <tr key={index} style={styles.tr}>
                  <td style={styles.td}><strong>{admin.name}</strong></td>
                  <td style={styles.td}>{admin.email}</td>
                  <td style={styles.td}>******</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <button 
        onClick={() => { localStorage.clear(); window.location.href = "/"; }} 
        style={styles.logoutBtn}
      >
        Keluar Sistem
      </button>
    </div>
  );
}

// 🎨 DESAIN CSS (Internal Styles)
const styles = {
  container: { padding: '40px', backgroundColor: '#f4f7f6', minHeight: '100vh', fontFamily: 'Segoe UI, sans-serif' },
  header: { marginBottom: '30px', textAlign: 'center' },
  title: { color: '#2c3e50', fontSize: '2.2rem', fontWeight: '800' },
  welcomeBox: { backgroundColor: '#d1edda', color: '#155724', padding: '10px 20px', borderRadius: '30px', display: 'inline-block', marginTop: '10px' },
  statsContainer: { display: 'flex', gap: '20px', marginBottom: '40px', justifyContent: 'center' },
  card: { backgroundColor: '#fff', padding: '20px', borderRadius: '15px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', minWidth: '250px', textAlign: 'center' },
  cardValue: { fontSize: '2rem', fontWeight: 'bold', color: '#3498db' },
  section: { marginBottom: '50px' },
  sectionTitle: { color: '#2c3e50', marginBottom: '15px', fontSize: '1.4rem' },
  tableContainer: { backgroundColor: '#fff', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 5px 20px rgba(0,0,0,0.05)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { backgroundColor: '#34495e', color: '#fff', padding: '15px', textAlign: 'left' },
  tr: { borderBottom: '1px solid #f1f1f1' },
  td: { padding: '15px', color: '#444' },
  progressBg: { backgroundColor: '#eee', borderRadius: '10px', height: '20px', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', overflow: 'hidden', fontSize: '0.75rem' },
  progressFill: { position: 'absolute', left: 0, height: '100%', backgroundColor: '#2ecc71', transition: 'width 0.5s ease' },
  badgeFull: { backgroundColor: '#e74c3c', color: '#fff', padding: '4px 10px', borderRadius: '10px', fontSize: '0.8rem' },
  badgeEmpty: { backgroundColor: '#27ae60', color: '#fff', padding: '4px 10px', borderRadius: '10px', fontSize: '0.8rem' },
  logoutBtn: { marginTop: '20px', padding: '10px 25px', backgroundColor: '#e74c3c', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }
};

export default Dashboard;
